import{_ as o,o as t,c as s,a2 as n}from"./chunks/framework.CHeM0PsO.js";const g=JSON.parse('{"title":"RFC 0013 — Mobile responsiveness & PWA hardening","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0013-mobile-responsiveness-pwa.md","filePath":"rfcs/0013-mobile-responsiveness-pwa.md"}'),a={name:"rfcs/0013-mobile-responsiveness-pwa.md"};function i(r,e,d,l,c,h){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="rfc-0013-—-mobile-responsiveness-pwa-hardening" tabindex="-1">RFC 0013 — Mobile responsiveness &amp; PWA hardening <a class="header-anchor" href="#rfc-0013-—-mobile-responsiveness-pwa-hardening" aria-label="Permalink to &quot;RFC 0013 — Mobile responsiveness &amp; PWA hardening&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> Runtime shell (<code>runtime/app/(platform)/</code>), <code>packages/ui</code> (<code>Dialog</code> + a new <code>Drawer</code> + tokens), runtime PWA config / <code>runtime/public/manifest.json</code> / root-layout viewport, <code>docs/design-system.md</code>, SRS; builds on RFC 0001 (overlay shell)<br><strong>Incorporated into plan:</strong> Yes — scheduled as roadmap Task 0.5.26; documentation-first. This RFC specifies the design and the end-to-end mobile UI flows; SRS requirement IDs, scheduling, and task allocation are deferred. Wiring the <code>minimal</code> shell mode is explicitly out of scope here and handed to a follow-up RFC 0014.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Harden Sovereign&#39;s <strong>mobile</strong> experience and its <strong>PWA</strong> so the installed app feels native, not like a desktop layout squeezed onto a phone. The work spans the three shell modes and a set of cross-cutting concerns:</p><ul><li><strong>Default shell (mobile):</strong> the persistent footer icon strip becomes a thin footer bar with a single action button that opens a dismissable <strong>bottom Drawer</strong> holding plugin navigation; the header gains an <strong>active-plugin title</strong>; Console (admin) moves into the <strong>header avatar menu</strong>.</li><li><strong>Minimal shell:</strong> the plugin owns the whole viewport — this RFC specifies its <strong>responsive expectations</strong> (full <code>dvh</code> height, <code>viewport-fit=cover</code>, safe-area pass-through) but <strong>does not wire the mode</strong> (→ RFC 0014).</li><li><strong>Overlay shell (mobile):</strong> an open dialog no longer covers the header — a new <code>--sv-dialog-inset-top</code> (mirror of the existing <code>--sv-dialog-inset-left</code>) keeps the fixed header <strong>visible and usable</strong> above the sheet, for all sizes.</li><li><strong>Cross-cutting:</strong> unify the inconsistent hardcoded breakpoints, switch the shell to <code>dvh</code>, add safe-area handling, enforce 44px touch targets, and polish the web app manifest (<code>display_override</code>, <code>shortcuts</code>, <code>screenshots</code>, <code>orientation</code>, immersive iOS status bar).</li><li><strong>Design system:</strong> a reusable <strong><code>Drawer</code></strong> primitive, new tokens (<code>--sv-dialog-inset-top</code>, <code>--sv-touch-target-min</code>), a documented <strong>breakpoint convention</strong>, and the first responsive/mobile guidance in <code>docs/design-system.md</code>.</li></ul><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Sovereign is positioned as an installable PWA (PLT-09, SRS §3.11) and a future Capacitor shell (SRS §3.12) will load the same instance unchanged — so the web mobile layout <em>is</em> the mobile app. The chrome is already responsive (PLT-13), but the experience is unhardened in ways that show immediately on a real phone:</p><ul><li>An open <strong>overlay</strong> plugin (Console, Account) becomes a full-screen sheet that <strong>covers the header</strong>, so the user loses branding, title, and any sense of where they are.</li><li><strong>Breakpoints disagree</strong> — the shell flips at <code>768px</code>, the Dialog at <code>640px</code> — producing a band (641–768px) where the shell is in mobile layout but the dialog is still a desktop box.</li><li>The shell&#39;s <code>min-height: 100vh</code> is <strong>clipped by mobile browser UI and the virtual keyboard</strong> (the offline page already uses <code>100dvh</code>, proving the fix).</li><li><strong>No safe-area handling</strong> means chrome collides with the notch and the home indicator once installed (<code>display: standalone</code>).</li><li><strong>Touch targets</strong> are ~36–40px, below the 44–48px guideline.</li><li>The <strong>manifest</strong> is functional but lacks the polish that makes an install feel first-class.</li><li><code>docs/design-system.md</code> gives plugin developers <strong>no</strong> responsive guidance.</li></ul><p>These are cheap, high-leverage wins that make the PWA credible and set the baseline the Capacitor shell will inherit.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>One shell breakpoint, CSS-only.</strong> <code>runtime/app/(platform)/shell.module.css</code> defines a desktop grid (<code>--sv-shell-sidebar-width: 64px</code>, <code>:1–9</code>) and a single <code>@media (max-width: 768px)</code> block (<code>:104–138</code>) that hides the sidebar and shows a mobile <strong>header</strong> (branding + avatar menu) and a persistent <strong>footer launcher</strong> (plugin icons). No JS viewport watching; all chrome is in the DOM and toggled by <code>display</code>.</li><li><strong>The avatar menu</strong> (<code>runtime/app/(platform)/_components/AccountMenu.tsx</code>) already renders in two placements (<code>sidebar</code> opens right, <code>header</code> opens down-left), with <code>aria-expanded</code>, Esc, and click-outside — the natural place to add Console for admins.</li><li><strong>Overlay dialog (RFC 0001).</strong> <code>packages/ui/src/components/Dialog/Dialog.tsx</code> renders fixed-size boxes (sm/md/lg); the scrim offsets its left edge by <code>--sv-dialog-inset-left</code> (the shell sets it to the sidebar width on desktop, <code>0</code> on mobile). On mobile, <code>Dialog.module.css</code> <code>@media (max-width: 640px)</code> (<code>:100–118</code>) makes <strong>every size a full-screen sheet</strong> (width/height 100%, no radius, scrim padding <code>0</code>) — which <strong>covers the header</strong>. Size is resolved per plugin from <code>shellConfig.overlaySize</code> via <code>overlaySizeForSegment</code> (<code>runtime/src/overlay.ts</code>).</li><li><strong><code>dvh</code> precedent.</strong> <code>runtime/app/offline/page.tsx</code> uses <code>min-height: 100dvh</code>; the shell still uses <code>100vh</code>.</li><li><strong>PWA surface.</strong> <code>runtime/public/manifest.json</code> has <code>display: &quot;standalone&quot;</code>, <code>theme_color</code>/<code>background_color</code> <code>#09090b</code>, and 192/512/maskable icons. <code>runtime/app/layout.tsx</code> links the manifest, sets <code>appleWebApp.statusBarStyle: &quot;default&quot;</code>, and exports <code>viewport.themeColor</code> — but <strong>no <code>viewport-fit=cover</code></strong> and no safe-area CSS anywhere.</li><li><strong>Tokens &amp; components.</strong> Plain CSS Modules + global <code>--sv-*</code> tokens (primitive + semantic tiers, <code>packages/ui/src/tokens/</code>), <strong>no Tailwind</strong>, <strong>no breakpoint token</strong> (CSS custom properties can&#39;t be used in <code>@media</code> conditions). The shipped component inventory is small — <strong>Button, Input, Dialog</strong>.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="shell-—-default-mobile" tabindex="-1">Shell — <code>default</code> (mobile) <a class="header-anchor" href="#shell-—-default-mobile" aria-label="Permalink to &quot;Shell — \`default\` (mobile)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Sovereign        &lt;Plugin title&gt;     ( ◐ ) │  header: brand · title · avatar menu</span></span>
<span class="line"><span>│                                            │   (avatar menu: Account · Console* · Log out)</span></span>
<span class="line"><span>├───────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                            │</span></span>
<span class="line"><span>│                content                     │  scrollable, 100dvh-aware</span></span>
<span class="line"><span>│                                            │</span></span>
<span class="line"><span>├───────────────────────────────────────────┤</span></span>
<span class="line"><span>│                 [ ▤ Apps ]                 │  footer bar: one action button</span></span>
<span class="line"><span>└───────────────────────────────────────────┘</span></span>
<span class="line"><span>                     │ tap</span></span>
<span class="line"><span>                     ▼</span></span>
<span class="line"><span>┌───────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ░░░░░░░░░░ scrim (header still shows) ░░░░ │</span></span>
<span class="line"><span>│            ┌───────────────────┐           │</span></span>
<span class="line"><span>│            │  Plugin navigation │  ← Drawer slides up from the bottom,</span></span>
<span class="line"><span>│            │  ▦  ▦  ▦  ▦         │     dismiss via scrim tap / Esc / swipe-down</span></span>
<span class="line"><span>│            └───────────────────┘           │</span></span>
<span class="line"><span>└───────────────────────────────────────────┘</span></span>
<span class="line"><span>   * Console row shown to platform:admin only</span></span></code></pre></div><ul><li><strong>Header</strong> = branding + <strong>active-plugin title</strong> + avatar menu. The title is resolved by the shell from the registry for the current route — <strong>no new plugin API</strong>; a plugin that later wants a <em>dynamic</em> title is an open question.</li><li><strong>Avatar menu</strong> gains a <strong>Console</strong> row for admins, beside Account and Log out — the mobile analog of the desktop sidebar&#39;s bottom chrome (where ⚙ Console and the avatar already sit together). This keeps the Drawer single-purpose.</li><li><strong>Footer</strong> = a thin bar with a single action button (&quot;Apps&quot;) that opens the <strong>Drawer</strong>. The Drawer is hidden by default, holds the <strong>plugin navigation</strong> (the launcher icons/list that the desktop sidebar&#39;s middle section shows), and is dismissable by scrim tap, Esc, or swipe-down. It is focus-trapped and safe-area-aware (bottom inset).</li></ul><h3 id="shell-—-minimal-mobile-—-responsive-expectations-only" tabindex="-1">Shell — <code>minimal</code> (mobile — responsive expectations only) <a class="header-anchor" href="#shell-—-minimal-mobile-—-responsive-expectations-only" aria-label="Permalink to &quot;Shell — \`minimal\` (mobile — responsive expectations only)&quot;">​</a></h3><p><code>minimal</code> plugins render <strong>no platform chrome</strong> — the plugin owns the entire viewport. This RFC specifies what the platform still guarantees on mobile:</p><ul><li>the viewport is <code>100dvh</code> (not <code>100vh</code>), so the plugin can fill the screen without keyboard/browser-UI clipping;</li><li><code>viewport-fit=cover</code> is set and <strong>safe-area insets are made available</strong> (<code>env(safe-area-inset-*)</code>) so a full-bleed plugin can choose to honour or ignore them;</li><li>no header, footer, sidebar, or Drawer is rendered.</li></ul><p><strong>Wiring the <code>minimal</code> route group itself is out of scope here</strong> — the generate script still fails the build on <code>shell: &quot;minimal&quot;</code> (<code>scripts/generate-registry.ts</code>). That work, and the rest of minimal&#39;s missing pieces, is handed to <strong>RFC 0014</strong>.</p><h3 id="shell-—-overlay-mobile" tabindex="-1">Shell — <code>overlay</code> (mobile) <a class="header-anchor" href="#shell-—-overlay-mobile" aria-label="Permalink to &quot;Shell — \`overlay\` (mobile)&quot;">​</a></h3><p>Today a mobile overlay covers everything. Instead, mirror the existing desktop left-inset pattern on the vertical axis:</p><ul><li>Add <strong><code>--sv-dialog-inset-top</code></strong> (default <code>0</code>), consumed by the <code>Dialog</code> scrim exactly as <code>--sv-dialog-inset-left</code> is.</li><li>On mobile the shell sets <code>--sv-dialog-inset-top</code> to the <strong>header height</strong> (and, as today, <code>--sv-dialog-inset-left: 0</code>). The fixed header stays painted and interactive <strong>above</strong> the sheet; the scrim and panel begin <strong>below</strong> it.</li><li>All sizes (sm/md/lg) become a full-width sheet filling the <strong>remaining</strong> height below the header on mobile (unchanged desktop behaviour). The unified breakpoint (below) replaces the Dialog&#39;s separate <code>640px</code> query.</li><li><strong>Layering:</strong> the header&#39;s <code>z-index</code> must be <code>≥</code> the scrim&#39;s (<code>100</code>) so it stays clickable while the dialog is open. Intra-overlay <code>&lt;Link replace&gt;</code> navigation and <code>router.back()</code> dismissal (RFC 0001) are unchanged.</li></ul><h3 id="cross-cutting-hardening" tabindex="-1">Cross-cutting hardening <a class="header-anchor" href="#cross-cutting-hardening" aria-label="Permalink to &quot;Cross-cutting hardening&quot;">​</a></h3><ul><li><strong>Breakpoint convention.</strong> Unify on a <strong>single mobile breakpoint — <code>768px</code></strong> — and migrate the Dialog from <code>640px</code> to it so the shell and the dialog flip together (eliminating the 641–768px mismatch band). Because CSS custom properties <strong>cannot</strong> be referenced inside <code>@media</code> conditions, the breakpoint is a <strong>documented constant</strong> (a future option is a PostCSS <code>@custom-media</code> token if build tooling is added) — <em>not</em> a <code>--sv-*</code> variable. Documented in <code>docs/design-system.md</code>.</li><li><strong>Dynamic viewport height.</strong> Shell <code>min-height: 100vh</code> → <code>100dvh</code> with a <code>100vh</code> fallback line for older engines.</li><li><strong>Safe areas.</strong> Add <code>viewport-fit=cover</code> to the <code>viewport</code> export (<code>runtime/app/layout.tsx</code>) and apply <code>env(safe-area-inset-*)</code> to the header (top), the footer bar / Drawer (bottom), and full-screen surfaces, so chrome clears the notch and home indicator in standalone mode.</li><li><strong>Touch targets.</strong> Minimum <strong>44px</strong> hit area for icon-only controls (header avatar, footer button, Drawer/sidebar icons). Introduce <strong><code>--sv-touch-target-min: 44px</code></strong> and apply it in the chrome and design-system components.</li><li><strong>Manifest polish</strong> (<code>runtime/public/manifest.json</code>): add <code>display_override: [&quot;standalone&quot;, &quot;minimal-ui&quot;]</code>, <code>categories: [&quot;productivity&quot;]</code>, <code>orientation</code> (value is an open question — <code>any</code> vs <code>portrait</code>), <code>shortcuts</code> (e.g. Launcher, Account), and <code>screenshots</code> (richer install dialog). In <code>runtime/app/layout.tsx</code>, switch <code>appleWebApp.statusBarStyle</code> to <code>&quot;black-translucent&quot;</code> for an immersive top, paired with the safe-area top inset.</li></ul><h3 id="design-system-additions-packages-ui" tabindex="-1">Design-system additions (<code>packages/ui</code>) <a class="header-anchor" href="#design-system-additions-packages-ui" aria-label="Permalink to &quot;Design-system additions (\`packages/ui\`)&quot;">​</a></h3><ul><li><strong><code>Drawer</code></strong> — a reusable bottom-sheet primitive: scrim + panel that slides up from the bottom, a <code>maxHeight</code>/size prop, focus trap, dismissal by Esc / scrim tap / swipe-down, and safe-area-aware bottom padding. Reuses <code>--sv-color-scrim</code> and <code>--sv-shadow-overlay</code>; shares the dismissal/focus conventions of <code>Dialog</code>. Additive — a <strong>minor</strong> <code>@sovereignfs/ui</code> bump.</li><li><strong>New tokens</strong> — <code>--sv-dialog-inset-top</code> and <code>--sv-touch-target-min</code> (additive).</li><li><strong><code>docs/design-system.md</code></strong> gains its first <strong>Responsive &amp; mobile</strong> section: the breakpoint convention, touch-target minimum, safe-area usage, <code>dvh</code>, and when to reach for <code>Dialog</code> vs <code>Drawer</code> — guidance plugin developers currently lack.</li></ul><h2 id="ui-flows" tabindex="-1">UI flows <a class="header-anchor" href="#ui-flows" aria-label="Permalink to &quot;UI flows&quot;">​</a></h2><p><strong>Navigate via the Drawer</strong> — mobile default shell → tap the footer <strong>Apps</strong> button → Drawer slides up over a scrim (header still visible) → tap a plugin → route changes and the Drawer dismisses; or dismiss with scrim tap / Esc / swipe-down with no navigation.</p><p><strong>Open an overlay plugin on mobile</strong> — tap Account (header avatar menu) or, for admins, Console → the overlay sheet rises <strong>below the fixed header</strong>, which stays showing branding + title → interact, switch tabs (<code>replace</code> nav) → Esc / scrim tap above the sheet / back gesture dismisses via <code>router.back()</code>.</p><p><strong>Admin reaches Console</strong> — open the header avatar menu → <strong>Console</strong> row (shown to <code>platform:admin</code> only) → Console opens as the top-inset overlay.</p><p><strong>Minimal plugin, edge to edge</strong> — a <code>minimal</code> plugin renders full-bleed across <code>100dvh</code> with no chrome; it reads <code>env(safe-area-inset-*)</code> if it wants to keep controls clear of the notch/home indicator. (Mode wiring lands in RFC 0014.)</p><p><strong>Install &amp; launch standalone</strong> — install from the browser → launch from the home screen → splash uses <code>background_color</code> → app opens in <code>standalone</code> with the header padded below the status bar (safe-area top) and the footer bar above the home indicator (safe-area bottom).</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Keep the persistent footer icon strip.</strong> Rejected — it clutters a small viewport, leaves no room for a header title, and grows unusable as the installed plugin count rises. A dismissable Drawer scales and declutters.</li><li><strong>Overlay as a bottom sheet on mobile</strong> (instead of top-inset). More &quot;mobile-native&quot;, but it introduces an interaction model that diverges from the desktop overlay. Top-inset reuses the existing <code>--sv-dialog-inset-*</code> pattern and keeps desktop/mobile consistent — chosen.</li><li><strong>Console in the bottom Drawer.</strong> Workable, and the user&#39;s initial instinct, but it mixes personal/admin chrome with app navigation. Putting Console in the header menu mirrors the desktop bottom chrome and keeps the Drawer single-purpose. Recorded as the alternative.</li><li><strong>Per-component breakpoints.</strong> The current 640/768 split <em>is</em> the bug; a single documented breakpoint prevents drift.</li><li><strong>JS viewport watcher / container queries everywhere.</strong> Rejected for the shell — CSS media queries keep SSR/RSC clean with no layout shift on resize. (Container queries remain fair game inside individual components later.)</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong><code>orientation</code></strong> — lock to <code>portrait</code>, or leave <code>any</code> (tablets/landscape)?</li><li><strong>Drawer variant</strong> — should the Drawer also offer a richer launcher-<em>grid</em> variant (name + icon tiles), or stay a compact nav list?</li><li><strong>Dynamic header title</strong> — route-derived plugin name covers the common case; do we need a plugin-set dynamic title (Next metadata vs a small SDK hook), and when?</li><li><strong><code>share_target</code></strong> — add &quot;Share to Sovereign&quot; to the manifest as a later enhancement?</li><li><strong>Minimal × safe-area</strong> — exactly how minimal&#39;s safe-area guarantees interact with RFC 0014&#39;s route-group wiring.</li><li><strong>Requirement IDs</strong> — proposed new PLT-/NFR- entries (mobile shell + PWA polish) are <strong>not</strong> assigned in the SRS until this RFC is accepted.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Documentation-first (this RFC).</strong> Design + UI flows captured; no code, no manifest/CSS changes, no SRS edits, no scheduling.</li><li><strong>When accepted &amp; scheduled</strong> (a runtime + <code>packages/ui</code> change): the <code>Drawer</code> primitive + new tokens (additive <strong>minor</strong> UI bump), the default-shell header/footer/Drawer rework, the overlay top-inset, and the cross-cutting hardening (breakpoint unification, <code>dvh</code>, safe-area, touch targets, manifest polish). The <code>docs/design-system.md</code> responsive section ships in the same change.</li><li><strong>RFC 0014 — Minimal shell mode</strong> follows immediately: wire the chrome-free route group and the rest of minimal&#39;s missing pieces, honouring the responsive expectations specified here.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; mobile hardening across the three shell modes + PWA polish; bottom <code>Drawer</code>, top-inset overlay, unified breakpoint, safe-area/<code>dvh</code>/touch-target tokens; documentation-first, minimal-mode wiring deferred to RFC 0014.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Accepted; scheduled in the roadmap as Task 0.5.26.</td></tr></tbody></table>`,41)])])}const m=o(a,[["render",i]]);export{g as __pageData,m as default};
